import XCTest
import CryptoKit
import Foundation
@testable import Echo

/// Cross-platform crypto tests that validate the same test vectors used by the Go backend.
/// Both platforms must produce identical results for key derivation, encryption, and decryption.
///
/// The test vectors are generated by: `go run test/crypto_vectors/generate_vectors.go`
/// and stored in: `test/crypto_vectors/vectors.json`

final class CrossPlatformCryptoTests: XCTestCase {

    // MARK: - Vector Models

    struct VectorFile: Codable {
        let vectors: [TestVector]
    }

    struct TestVector: Codable {
        let name: String
        let description: String
        let senderPrivateKey: String    // base64 P-256 scalar (32 bytes)
        let senderPublicKey: String     // base64 P-256 raw X||Y (64 bytes)
        let recipientPrivateKey: String
        let recipientPublicKey: String
        let derivedKey: String          // base64 HKDF output (32 bytes)
        let plaintext: String
        let nonce: String               // base64 12-byte GCM nonce
        let ciphertext: String          // base64 ciphertext
        let tag: String                 // base64 16-byte GCM tag

        enum CodingKeys: String, CodingKey {
            case name, description, plaintext, nonce, ciphertext, tag
            case senderPrivateKey = "sender_private_key"
            case senderPublicKey = "sender_public_key"
            case recipientPrivateKey = "recipient_private_key"
            case recipientPublicKey = "recipient_public_key"
            case derivedKey = "derived_key"
        }
    }

    // MARK: - Vector Loading

    /// Loads test vectors from the shared JSON file.
    /// Adjust the path if running from a different working directory.
    func loadVectors() throws -> [TestVector] {
        // Try multiple paths to find vectors.json
        let candidates = [
            // When running from ios/Echo/
            "../../test/crypto_vectors/vectors.json",
            // When running from project root
            "test/crypto_vectors/vectors.json",
            // Absolute fallback
            Bundle.module.path(forResource: "vectors", ofType: "json"),
        ].compactMap { $0 }

        var data: Data?
        for path in candidates {
            let url = URL(fileURLWithPath: path)
            if let d = try? Data(contentsOf: url) {
                data = d
                break
            }
        }

        // If file not found, use embedded vectors for CI reliability
        if data == nil {
            data = embeddedVectorsJSON.data(using: .utf8)
        }

        guard let jsonData = data else {
            XCTFail("Could not load vectors.json from any path")
            return []
        }

        let file = try JSONDecoder().decode(VectorFile.self, from: jsonData)
        XCTAssertGreaterThan(file.vectors.count, 0, "No vectors found")
        return file.vectors
    }

    // MARK: - Key Derivation Tests

    /// Verifies that Swift CryptoKit ECDH + HKDF produces the same derived key
    /// as the Go implementation for each test vector.
    func testKeyDerivation_matchesGoVectors() throws {
        let vectors = try loadVectors()

        for vec in vectors {
            // Decode sender's private key (32 bytes scalar)
            guard let senderPrivData = Data(base64Encoded: vec.senderPrivateKey),
                  let recipientPubData = Data(base64Encoded: vec.recipientPublicKey),
                  let expectedKey = Data(base64Encoded: vec.derivedKey) else {
                XCTFail("[\(vec.name)] Failed to decode base64 fields")
                continue
            }

            // Reconstruct P-256 keys
            let senderPrivKey = try P256.KeyAgreement.PrivateKey(rawRepresentation: senderPrivData)
            let recipientPubKey = try P256.KeyAgreement.PublicKey(rawRepresentation: recipientPubData)

            // ECDH key agreement
            let sharedSecret = try senderPrivKey.sharedSecretFromKeyAgreement(with: recipientPubKey)

            // HKDF derivation (must match Go: salt="ECHO-E2E-KINNAMI", info="message-encryption")
            let derivedKey = sharedSecret.hkdfDerivedSymmetricKey(
                using: SHA256.self,
                salt: Data("ECHO-E2E-KINNAMI".utf8),
                sharedInfo: Data("message-encryption".utf8),
                outputByteCount: 32
            )

            // Compare derived key bytes
            let derivedKeyData = derivedKey.withUnsafeBytes { Data($0) }
            XCTAssertEqual(
                derivedKeyData, expectedKey,
                "[\(vec.name)] Key derivation mismatch — Go and Swift produced different keys"
            )
        }
    }

    // MARK: - Decryption Tests

    /// Verifies that Swift can decrypt ciphertext that was encrypted by Go.
    func testDecryption_ofGoEncryptedData() throws {
        let vectors = try loadVectors()

        for vec in vectors {
            guard let keyData = Data(base64Encoded: vec.derivedKey),
                  let nonceData = Data(base64Encoded: vec.nonce),
                  let ctData = Data(base64Encoded: vec.ciphertext),
                  let tagData = Data(base64Encoded: vec.tag) else {
                XCTFail("[\(vec.name)] Failed to decode base64 fields")
                continue
            }

            let symmetricKey = SymmetricKey(data: keyData)
            let nonce = try AES.GCM.Nonce(data: nonceData)
            let sealedBox = try AES.GCM.SealedBox(nonce: nonce, ciphertext: ctData, tag: tagData)

            let decryptedData = try AES.GCM.open(sealedBox, using: symmetricKey)
            let plaintext = String(data: decryptedData, encoding: .utf8) ?? ""

            XCTAssertEqual(
                plaintext, vec.plaintext,
                "[\(vec.name)] Decrypted text doesn't match original plaintext"
            )
        }
    }

    // MARK: - Recipient Decryption (Full Flow)

    /// Verifies that the recipient can derive the same key using their private key
    /// + sender's public key, then decrypt the message.
    func testRecipientDecryption_fullFlow() throws {
        let vectors = try loadVectors()

        for vec in vectors {
            guard let recipientPrivData = Data(base64Encoded: vec.recipientPrivateKey),
                  let senderPubData = Data(base64Encoded: vec.senderPublicKey),
                  let nonceData = Data(base64Encoded: vec.nonce),
                  let ctData = Data(base64Encoded: vec.ciphertext),
                  let tagData = Data(base64Encoded: vec.tag),
                  let expectedKey = Data(base64Encoded: vec.derivedKey) else {
                XCTFail("[\(vec.name)] Failed to decode base64 fields")
                continue
            }

            // Recipient reconstructs their keys
            let recipientPrivKey = try P256.KeyAgreement.PrivateKey(rawRepresentation: recipientPrivData)
            let senderPubKey = try P256.KeyAgreement.PublicKey(rawRepresentation: senderPubData)

            // ECDH is symmetric: recipient(priv) × sender(pub) == sender(priv) × recipient(pub)
            let sharedSecret = try recipientPrivKey.sharedSecretFromKeyAgreement(with: senderPubKey)
            let derivedKey = sharedSecret.hkdfDerivedSymmetricKey(
                using: SHA256.self,
                salt: Data("ECHO-E2E-KINNAMI".utf8),
                sharedInfo: Data("message-encryption".utf8),
                outputByteCount: 32
            )

            // Verify key matches
            let derivedKeyData = derivedKey.withUnsafeBytes { Data($0) }
            XCTAssertEqual(
                derivedKeyData, expectedKey,
                "[\(vec.name)] Recipient derived a different key — ECDH symmetry broken"
            )

            // Decrypt
            let nonce = try AES.GCM.Nonce(data: nonceData)
            let sealedBox = try AES.GCM.SealedBox(nonce: nonce, ciphertext: ctData, tag: tagData)
            let decryptedData = try AES.GCM.open(sealedBox, using: derivedKey)
            let plaintext = String(data: decryptedData, encoding: .utf8) ?? ""

            XCTAssertEqual(
                plaintext, vec.plaintext,
                "[\(vec.name)] Recipient failed to decrypt message"
            )
        }
    }

    // MARK: - Tampered Ciphertext

    /// Verifies that modifying ciphertext causes AES-GCM authentication to fail.
    func testTamperedCiphertext_failsAuthentication() throws {
        let vectors = try loadVectors()

        for vec in vectors {
            guard let keyData = Data(base64Encoded: vec.derivedKey),
                  let nonceData = Data(base64Encoded: vec.nonce),
                  var ctData = Data(base64Encoded: vec.ciphertext),
                  let tagData = Data(base64Encoded: vec.tag) else {
                continue
            }

            // Skip empty ciphertext
            guard !ctData.isEmpty else { continue }

            // Flip a bit
            ctData[0] ^= 0xFF

            let symmetricKey = SymmetricKey(data: keyData)
            let nonce = try AES.GCM.Nonce(data: nonceData)
            let sealedBox = try AES.GCM.SealedBox(nonce: nonce, ciphertext: ctData, tag: tagData)

            XCTAssertThrowsError(
                try AES.GCM.open(sealedBox, using: symmetricKey),
                "[\(vec.name)] Tampered ciphertext should fail authentication"
            )
        }
    }

    // MARK: - Swift-to-Go Encryption (Round-trip Readiness)

    /// Verifies that Swift can encrypt a message and then decrypt it,
    /// proving that Swift-encrypted data could be decrypted by Go using the same key.
    func testSwiftEncrypt_GoCanDecrypt_sameKeyFormat() throws {
        let vectors = try loadVectors()

        for vec in vectors {
            guard let keyData = Data(base64Encoded: vec.derivedKey) else { continue }

            let symmetricKey = SymmetricKey(data: keyData)
            let plaintext = vec.plaintext

            // Encrypt with Swift
            guard let plaintextData = plaintext.data(using: .utf8) else { continue }
            let sealedBox = try AES.GCM.seal(plaintextData, using: symmetricKey)

            // Decrypt with Swift (proving format compatibility)
            let decryptedData = try AES.GCM.open(sealedBox, using: symmetricKey)
            let decrypted = String(data: decryptedData, encoding: .utf8) ?? ""

            XCTAssertEqual(decrypted, plaintext, "[\(vec.name)] Swift round-trip failed")

            // Verify the output format matches what Go expects:
            // nonce (12 bytes), ciphertext (variable), tag (16 bytes)
            let nonceData = sealedBox.nonce.withUnsafeBytes { Data($0) }
            XCTAssertEqual(nonceData.count, 12, "[\(vec.name)] Nonce should be 12 bytes")
            XCTAssertEqual(sealedBox.tag.count, 16, "[\(vec.name)] Tag should be 16 bytes")
        }
    }
}

